{"element_id":"7349cd7","elType":"widget","widgetType":"html","settings":{"html":"<style>
/* Home 2026 Hero floating card */
#home-2026-hero-wrap{position:relative;}
#home-2026-hero-float{position:absolute;left:56%;top:58%;transform:translate(-50%,-50%);width:220px;background:#fff;border-radius:18px;box-shadow:0 18px 50px rgba(20,20,20,.14);padding:14px 14px 12px;font-family:inherit;}
#home-2026-hero-float .row{display:flex;gap:10px;align-items:flex-start;}
#home-2026-hero-float .icon{width:34px;height:34px;border-radius:10px;background:#fff1e6;display:flex;align-items:center;justify-content:center;flex:0 0 auto;font-size:16px;}
#home-2026-hero-float .title{font-weight:700;font-size:14px;line-height:1.1;margin:2px 0 6px;color:#191919;}
#home-2026-hero-float .desc{font-size:12px;line-height:1.35;color:#4a4a4a;margin:0 0 10px;}
#home-2026-hero-float .bottom{display:flex;justify-content:space-between;align-items:center;gap:10px;}
#home-2026-hero-float .price{font-weight:800;color:#F07A1B;font-size:13px;white-space:nowrap;}
#home-2026-hero-float .badge{font-size:10px;font-weight:800;letter-spacing:.06em;padding:5px 8px;border-radius:999px;background:#e9f7ef;color:#1f7a3a;white-space:nowrap;}
@media (max-width: 767px){
  #home-2026-hero-float{left:50%;top:80%;width:210px;}
}
</style>
<div id="home-2026-hero-wrap">
  <div id="home-2026-hero-float">
    <div class="row">
      <div class="icon">🍽️</div>
      <div>
        <div class="title">Chef’s Special</div>
        <div class="desc">Maharaja Thali (Non-veg) — Combination of 7 items</div>
        <div class="bottom">
          <div class="price">From $15.00 CAD</div>
          <div class="badge">HIGH PROTEIN</div>
        </div>
      </div>
    </div>
  </div>
</div>"}}
